	internal class DuplexStream : Stream
	{
		private bool disposed;

		public Stream InputStream { get; private set; }

		public Stream OutputStream { get; private set; }

		public override bool CanRead => true;

		public override bool CanWrite => true;

		public override bool CanSeek => false;

		public override bool CanTimeout
		{
			get
			{
				if (InputStream.CanTimeout)
				{
					return OutputStream.CanTimeout;
				}
				return false;
			}
		}

		public override int ReadTimeout
		{
			get
			{
				return InputStream.ReadTimeout;
			}
			set
			{
				InputStream.ReadTimeout = value;
			}
		}

		public override int WriteTimeout
		{
			get
			{
				return OutputStream.WriteTimeout;
			}
			set
			{
				OutputStream.WriteTimeout = value;
			}
		}

		public override long Position
		{
			get
			{
				throw new NotSupportedException();
			}
			set
			{
				throw new NotSupportedException();
			}
		}

		public override long Length
		{
			get
			{
				throw new NotSupportedException();
			}
		}

		public DuplexStream(Stream istream, Stream ostream)
		{
			if (istream == null)
			{
				throw new ArgumentNullException("istream");
			}
			if (ostream == null)
			{
				throw new ArgumentNullException("ostream");
			}
			InputStream = istream;
			OutputStream = ostream;
		}

		private static void ValidateArguments(byte[] buffer, int offset, int count)
		{
			if (buffer == null)
			{
				throw new ArgumentNullException("buffer");
			}
			if (offset < 0 || offset > buffer.Length)
			{
				throw new ArgumentOutOfRangeException("offset");
			}
			if (count < 0 || count > buffer.Length - offset)
			{
				throw new ArgumentOutOfRangeException("count");
			}
		}

		private void CheckDisposed()
		{
			if (disposed)
			{
				throw new ObjectDisposedException("DuplexStream");
			}
		}

		public override int Read(byte[] buffer, int offset, int count)
		{
			CheckDisposed();
			ValidateArguments(buffer, offset, count);
			return InputStream.Read(buffer, offset, count);
		}

		public override Task<int> ReadAsync(byte[] buffer, int offset, int count, CancellationToken cancellationToken)
		{
			CheckDisposed();
			ValidateArguments(buffer, offset, count);
			return InputStream.ReadAsync(buffer, offset, count, cancellationToken);
		}

		public override void Write(byte[] buffer, int offset, int count)
		{
			CheckDisposed();
			ValidateArguments(buffer, offset, count);
			OutputStream.Write(buffer, offset, count);
		}

		public override Task WriteAsync(byte[] buffer, int offset, int count, CancellationToken cancellationToken)
		{
			CheckDisposed();
			ValidateArguments(buffer, offset, count);
			return OutputStream.WriteAsync(buffer, offset, count, cancellationToken);
		}

		public override void Flush()
		{
			CheckDisposed();
			OutputStream.Flush();
		}

		public override Task FlushAsync(CancellationToken cancellationToken)
		{
			CheckDisposed();
			return OutputStream.FlushAsync(cancellationToken);
		}

		public override long Seek(long offset, SeekOrigin origin)
		{
			throw new NotSupportedException();
		}

		public override void SetLength(long value)
		{
			throw new NotSupportedException();
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing && !disposed)
			{
				OutputStream.Dispose();
				InputStream.Dispose();
				disposed = true;
			}
			base.Dispose(disposing);
		}
	}
	public class Envelope
	{
		public InternetAddressList From { get; private set; }

		public InternetAddressList Sender { get; private set; }

		public InternetAddressList ReplyTo { get; private set; }

		public InternetAddressList To { get; private set; }

		public InternetAddressList Cc { get; private set; }

		public InternetAddressList Bcc { get; private set; }

		public string InReplyTo { get; set; }

		public DateTimeOffset? Date { get; set; }

		public string MessageId { get; set; }

		public string Subject { get; set; }

		public Envelope()
		{
			From = new InternetAddressList();
			Sender = new InternetAddressList();
			ReplyTo = new InternetAddressList();
			To = new InternetAddressList();
			Cc = new InternetAddressList();
			Bcc = new InternetAddressList();
		}

		private static void EncodeMailbox(StringBuilder builder, MailboxAddress mailbox)
		{
			builder.Append('(');
			if (mailbox.Name != null)
			{
				builder.AppendFormat("{0} ", MimeUtils.Quote(mailbox.Name));
			}
			else
			{
				builder.Append("NIL ");
			}
			if (mailbox.Route.Count != 0)
			{
				builder.AppendFormat("\"{0}\" ", mailbox.Route);
			}
			else
			{
				builder.Append("NIL ");
			}
			int num = mailbox.Address.LastIndexOf('@');
			if (num >= 0)
			{
				string text = mailbox.Address.Substring(num + 1);
				string text2 = mailbox.Address.Substring(0, num);
				builder.AppendFormat("{0} {1}", MimeUtils.Quote(text2), MimeUtils.Quote(text));
			}
			else
			{
				builder.AppendFormat("{0} \"localhost\"", MimeUtils.Quote(mailbox.Address));
			}
			builder.Append(')');
		}

		private static void EncodeInternetAddressListAddresses(StringBuilder builder, InternetAddressList addresses)
		{
			foreach (InternetAddress address in addresses)
			{
				MailboxAddress mailboxAddress = address as MailboxAddress;
				GroupAddress groupAddress = address as GroupAddress;
				if (mailboxAddress != null)
				{
					EncodeMailbox(builder, mailboxAddress);
				}
				else if (groupAddress != null)
				{
					EncodeGroup(builder, groupAddress);
				}
			}
		}

		private static void EncodeGroup(StringBuilder builder, GroupAddress group)
		{
			builder.AppendFormat("(NIL NIL {0} NIL)", MimeUtils.Quote(group.Name));
			EncodeInternetAddressListAddresses(builder, group.Members);
			builder.Append("(NIL NIL NIL NIL)");
		}

		private static void EncodeAddressList(StringBuilder builder, InternetAddressList list)
		{
			builder.Append('(');
			EncodeInternetAddressListAddresses(builder, list);
			builder.Append(')');
		}

		internal void Encode(StringBuilder builder)
		{
			builder.Append('(');
			if (Date.HasValue)
			{
				builder.AppendFormat("\"{0}\" ", DateUtils.FormatDate(Date.Value));
			}
			else
			{
				builder.Append("NIL ");
			}
			if (Subject != null)
			{
				builder.AppendFormat("{0} ", MimeUtils.Quote(Subject));
			}
			else
			{
				builder.Append("NIL ");
			}
			if (From.Count > 0)
			{
				EncodeAddressList(builder, From);
				builder.Append(' ');
			}
			else
			{
				builder.Append("NIL ");
			}
			if (Sender.Count > 0)
			{
				EncodeAddressList(builder, Sender);
				builder.Append(' ');
			}
			else
			{
				builder.Append("NIL ");
			}
			if (ReplyTo.Count > 0)
			{
				EncodeAddressList(builder, ReplyTo);
				builder.Append(' ');
			}
			else
			{
				builder.Append("NIL ");
			}
			if (To.Count > 0)
			{
				EncodeAddressList(builder, To);
				builder.Append(' ');
			}
			else
			{
				builder.Append("NIL ");
			}
			if (Cc.Count > 0)
			{
				EncodeAddressList(builder, Cc);
				builder.Append(' ');
			}
			else
			{
				builder.Append("NIL ");
			}
			if (Bcc.Count > 0)
			{
				EncodeAddressList(builder, Bcc);
				builder.Append(' ');
			}
			else
			{
				builder.Append("NIL ");
			}
			if (InReplyTo != null)
			{
				if (InReplyTo.Length > 1 && InReplyTo[0] != '<' && InReplyTo[InReplyTo.Length - 1] != '>')
				{
					builder.AppendFormat("{0} ", MimeUtils.Quote("<" + InReplyTo + ">"));
				}
				else
				{
					builder.AppendFormat("{0} ", MimeUtils.Quote(InReplyTo));
				}
			}
			else
			{
				builder.Append("NIL ");
			}
			if (MessageId != null)
			{
				if (MessageId.Length > 1 && MessageId[0] != '<' && MessageId[MessageId.Length - 1] != '>')
				{
					builder.AppendFormat("{0}", MimeUtils.Quote("<" + MessageId + ">"));
				}
				else
				{
					builder.AppendFormat("{0}", MimeUtils.Quote(MessageId));
				}
			}
			else
			{
				builder.Append("NIL");
			}
			builder.Append(')');
		}

