	public class FolderNamespaceCollection : IEnumerable<FolderNamespace>, IEnumerable
	{
		private readonly List<FolderNamespace> namespaces;

		public int Count => namespaces.Count;

		public FolderNamespace this[int index]
		{
			get
			{
				if (index < 0 || index >= namespaces.Count)
				{
					throw new ArgumentOutOfRangeException("index");
				}
				return namespaces[index];
			}
			set
			{
				if (index < 0 || index >= namespaces.Count)
				{
					throw new ArgumentOutOfRangeException("index");
				}
				if (value == null)
				{
					throw new ArgumentNullException("value");
				}
				namespaces[index] = value;
			}
		}

		public FolderNamespaceCollection()
		{
			namespaces = new List<FolderNamespace>();
		}

		public void Add(FolderNamespace @namespace)
		{
			if (@namespace == null)
			{
				throw new ArgumentNullException("namespace");
			}
			namespaces.Add(@namespace);
		}

		public void Clear()
		{
			namespaces.Clear();
		}

		public bool Contains(FolderNamespace @namespace)
		{
			if (@namespace == null)
			{
				throw new ArgumentNullException("namespace");
			}
			return namespaces.Contains(@namespace);
		}

		public bool Remove(FolderNamespace @namespace)
		{
			if (@namespace == null)
			{
				throw new ArgumentNullException("namespace");
			}
			return namespaces.Remove(@namespace);
		}

		public IEnumerator<FolderNamespace> GetEnumerator()
		{
			return namespaces.GetEnumerator();
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return namespaces.GetEnumerator();
		}

		private static bool Escape(char directorySeparator)
		{
			if (directorySeparator != '\\')
			{
				return directorySeparator == '"';
			}
			return true;
		}

		public override string ToString()
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append('(');
			for (int i = 0; i < namespaces.Count; i++)
			{
				stringBuilder.Append("(\"");
				if (Escape(namespaces[i].DirectorySeparator))
				{
					stringBuilder.Append('\\');
				}
				stringBuilder.Append(namespaces[i].DirectorySeparator);
				stringBuilder.Append("\" ");
				stringBuilder.Append(MimeUtils.Quote(namespaces[i].Path));
				stringBuilder.Append(")");
			}
			stringBuilder.Append(')');
			return stringBuilder.ToString();
		}
	}
	[Serializable]
	public class FolderNotFoundException : Exception
	{
		public string FolderName { get; private set; }

		protected FolderNotFoundException(SerializationInfo info, StreamingContext context)
			: base(info, context)
		{
			FolderName = info.GetString("FolderName");
		}

		public FolderNotFoundException(string message, string folderName, Exception innerException)
			: base(message, innerException)
		{
			if (folderName == null)
			{
				throw new ArgumentNullException("folderName");
			}
			FolderName = folderName;
		}

		public FolderNotFoundException(string message, string folderName)
			: base(message)
		{
			if (folderName == null)
			{
				throw new ArgumentNullException("folderName");
			}
			FolderName = folderName;
		}

		public FolderNotFoundException(string folderName)
			: this("The requested folder could not be found.", folderName)
		{
		}

		[SecurityCritical]
		public override void GetObjectData(SerializationInfo info, StreamingContext context)
		{
			base.GetObjectData(info, context);
			info.AddValue("FolderName", FolderName);
		}
	}
	[Serializable]
	public class FolderNotOpenException : InvalidOperationException
	{
		public string FolderName { get; private set; }

		public FolderAccess FolderAccess { get; private set; }

		protected FolderNotOpenException(SerializationInfo info, StreamingContext context)
			: base(info, context)
		{
			if (!Enum.TryParse<FolderAccess>(info.GetString("FolderAccess"), out var result))
			{
				FolderAccess = FolderAccess.ReadOnly;
			}
			else
			{
				FolderAccess = result;
			}
			FolderName = info.GetString("FolderName");
		}

		public FolderNotOpenException(string folderName, FolderAccess access, string message, Exception innerException)
			: base(message, innerException)
		{
			if (folderName == null)
			{
				throw new ArgumentNullException("folderName");
			}
			FolderName = folderName;
			FolderAccess = access;
		}

		public FolderNotOpenException(string folderName, FolderAccess access, string message)
			: base(message)
		{
			if (folderName == null)
			{
				throw new ArgumentNullException("folderName");
			}
			FolderName = folderName;
			FolderAccess = access;
		}

		public FolderNotOpenException(string folderName, FolderAccess access)
			: this(folderName, access, GetDefaultMessage(access))
		{
		}

		private static string GetDefaultMessage(FolderAccess access)
		{
			if (access == FolderAccess.ReadWrite)
			{
				return "The folder is not currently open in read-write mode.";
			}
			return "The folder is not currently open.";
		}

		public override void GetObjectData(SerializationInfo info, StreamingContext context)
		{
			base.GetObjectData(info, context);
			info.AddValue("FolderAccess", FolderAccess.ToString());
			info.AddValue("FolderName", FolderName);
		}
	}
