	public class ProtocolLogger : IProtocolLogger, IDisposable
	{
		private static readonly byte[] ClientPrefix = Encoding.ASCII.GetBytes("C: ");

		private static readonly byte[] ServerPrefix = Encoding.ASCII.GetBytes("S: ");

		private readonly Stream stream;

		private readonly bool leaveOpen;

		private bool clientMidline;

		private bool serverMidline;

		public ProtocolLogger(string fileName, bool append = true)
		{
			stream = File.Open(fileName, append ? FileMode.Append : FileMode.Create, FileAccess.Write, FileShare.Read);
		}

		public ProtocolLogger(Stream stream, bool leaveOpen = false)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			this.leaveOpen = leaveOpen;
			this.stream = stream;
		}

		~ProtocolLogger()
		{
			Dispose(disposing: false);
		}

		private static void ValidateArguments(byte[] buffer, int offset, int count)
		{
			if (buffer == null)
			{
				throw new ArgumentNullException("buffer");
			}
			if (offset < 0 || offset > buffer.Length)
			{
				throw new ArgumentOutOfRangeException("offset");
			}
			if (count < 0 || count > buffer.Length - offset)
			{
				throw new ArgumentOutOfRangeException("count");
			}
		}

		private void Log(byte[] prefix, ref bool midline, byte[] buffer, int offset, int count)
		{
			int num = offset + count;
			int i = offset;
			while (i < num)
			{
				int num2 = i;
				for (; i < num && buffer[i] != 10; i++)
				{
				}
				if (!midline)
				{
					stream.Write(prefix, 0, prefix.Length);
				}
				if (i < num && buffer[i] == 10)
				{
					midline = false;
					i++;
				}
				else
				{
					midline = true;
				}
				stream.Write(buffer, num2, i - num2);
			}
			stream.Flush();
		}

		public void LogConnect(Uri uri)
		{
			if (uri == null)
			{
				throw new ArgumentNullException("uri");
			}
			string s = $"Connected to {uri}\r\n";
			byte[] bytes = Encoding.ASCII.GetBytes(s);
			if (clientMidline || serverMidline)
			{
				stream.WriteByte(13);
				stream.WriteByte(10);
				clientMidline = false;
				serverMidline = false;
			}
			stream.Write(bytes, 0, bytes.Length);
			stream.Flush();
		}

		public void LogClient(byte[] buffer, int offset, int count)
		{
			ValidateArguments(buffer, offset, count);
			Log(ClientPrefix, ref clientMidline, buffer, offset, count);
		}

		public void LogServer(byte[] buffer, int offset, int count)
		{
			ValidateArguments(buffer, offset, count);
			Log(ServerPrefix, ref serverMidline, buffer, offset, count);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposing && !leaveOpen)
			{
				stream.Dispose();
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}
	}
