	[Serializable]
	public class AuthenticationException : Exception
	{
		protected AuthenticationException(SerializationInfo info, StreamingContext context)
			: base(info, context)
		{
		}

		public AuthenticationException(string message, Exception innerException)
			: base(message, innerException)
		{
		}

		public AuthenticationException(string message)
			: base(message)
		{
		}

		public AuthenticationException()
			: base("Authentication failed.")
		{
		}
	}
	public enum SaslErrorCode
	{
		ChallengeTooLong,
		IncompleteChallenge,
		InvalidChallenge,
		MissingChallenge,
		IncorrectHash
	}
	[Serializable]
	public class SaslException : AuthenticationException
	{
		public SaslErrorCode ErrorCode { get; private set; }

		public string Mechanism { get; private set; }

		protected SaslException(SerializationInfo info, StreamingContext context)
			: base(info, context)
		{
			ErrorCode = (SaslErrorCode)info.GetInt32("ErrorCode");
			Mechanism = info.GetString("Mechanism");
		}

		public SaslException(string mechanism, SaslErrorCode code, string message)
			: base(message)
		{
			if (mechanism == null)
			{
				throw new ArgumentNullException("mechanism");
			}
			Mechanism = mechanism;
			ErrorCode = code;
		}

		[SecurityCritical]
		public override void GetObjectData(SerializationInfo info, StreamingContext context)
		{
			base.GetObjectData(info, context);
			info.AddValue("ErrorCode", (int)ErrorCode);
			info.AddValue("Mechanism", Mechanism);
		}
	}
	public abstract class SaslMechanism
	{
		public static readonly string[] AuthMechanismRank = new string[6] { "SCRAM-SHA-256", "SCRAM-SHA-1", "CRAM-MD5", "DIGEST-MD5", "PLAIN", "LOGIN" };

		public abstract string MechanismName { get; }

		public NetworkCredential Credentials { get; private set; }

		public virtual bool SupportsInitialResponse => false;

		public bool IsAuthenticated { get; protected set; }

		public virtual bool NegotiatedSecurityLayer => false;

		internal Uri Uri { get; set; }

		[Obsolete("Use SaslMechanism(NetworkCredential) instead.")]
		protected SaslMechanism(Uri uri, ICredentials credentials)
		{
			if (uri == null)
			{
				throw new ArgumentNullException("uri");
			}
			if (credentials == null)
			{
				throw new ArgumentNullException("credentials");
			}
			Credentials = credentials.GetCredential(uri, MechanismName);
			Uri = uri;
		}

		[Obsolete("Use SaslMechanism(string, string) instead.")]
		protected SaslMechanism(Uri uri, string userName, string password)
		{
			if (uri == null)
			{
				throw new ArgumentNullException("uri");
			}
			if (userName == null)
			{
				throw new ArgumentNullException("userName");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			Credentials = new NetworkCredential(userName, password);
			Uri = uri;
		}

		protected SaslMechanism(NetworkCredential credentials)
		{
			if (credentials == null)
			{
				throw new ArgumentNullException("credentials");
			}
			Credentials = credentials;
		}

		protected SaslMechanism(string userName, string password)
		{
			if (userName == null)
			{
				throw new ArgumentNullException("userName");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			Credentials = new NetworkCredential(userName, password);
		}

		protected abstract byte[] Challenge(byte[] token, int startIndex, int length);

		public string Challenge(string token)
		{
			byte[] array = null;
			int length = 0;
			if (token != null)
			{
				try
				{
					array = Convert.FromBase64String(token.Trim());
					length = array.Length;
				}
				catch (FormatException)
				{
				}
			}
			byte[] array2 = Challenge(array, 0, length);
			if (array2 == null)
			{
				return null;
			}
			return Convert.ToBase64String(array2);
		}

		public virtual void Reset()
		{
			IsAuthenticated = false;
		}

		public static bool IsSupported(string mechanism)
		{
			if (mechanism == null)
			{
				throw new ArgumentNullException("mechanism");
			}
			return mechanism switch
			{
				"SCRAM-SHA-256" => true, 
				"SCRAM-SHA-1" => true, 
				"DIGEST-MD5" => true, 
				"CRAM-MD5" => true, 
				"XOAUTH2" => true, 
				"PLAIN" => true, 
				"LOGIN" => true, 
				"NTLM" => true, 
				_ => false, 
			};
		}

		public static SaslMechanism Create(string mechanism, Uri uri, Encoding encoding, ICredentials credentials)
		{
			if (mechanism == null)
			{
				throw new ArgumentNullException("mechanism");
			}
			if (uri == null)
			{
				throw new ArgumentNullException("uri");
			}
			if (encoding == null)
			{
				throw new ArgumentNullException("encoding");
			}
			if (credentials == null)
			{
				throw new ArgumentNullException("credentials");
			}
			NetworkCredential credential = credentials.GetCredential(uri, mechanism);
			return mechanism switch
			{
				"SCRAM-SHA-256" => new SaslMechanismScramSha256(credential)
				{
					Uri = uri
				}, 
				"SCRAM-SHA-1" => new SaslMechanismScramSha1(credential)
				{
					Uri = uri
				}, 
				"DIGEST-MD5" => new SaslMechanismDigestMd5(credential)
				{
					Uri = uri
				}, 
				"CRAM-MD5" => new SaslMechanismCramMd5(credential)
				{
					Uri = uri
				}, 
				"XOAUTH2" => new SaslMechanismOAuth2(credential)
				{
					Uri = uri
				}, 
				"PLAIN" => new SaslMechanismPlain(encoding, credential)
				{
					Uri = uri
				}, 
				"LOGIN" => new SaslMechanismLogin(encoding, credential)
				{
					Uri = uri
				}, 
				"NTLM" => new SaslMechanismNtlm(credential)
				{
					Uri = uri
				}, 
				_ => null, 
			};
		}

		public static SaslMechanism Create(string mechanism, Uri uri, ICredentials credentials)
		{
			return Create(mechanism, uri, Encoding.UTF8, credentials);
		}

