	[Serializable]
	public class SslHandshakeException : Exception
	{
		private const string SslHandshakeHelpLink = "https://github.com/jstedfast/MailKit/blob/master/FAQ.md#InvalidSslCertificate";

		private const string DefaultMessage = "An error occurred while attempting to establish an SSL or TLS connection.";

		protected SslHandshakeException(SerializationInfo info, StreamingContext context)
			: base(info, context)
		{
		}

		public SslHandshakeException(string message, Exception innerException)
			: base(message, innerException)
		{
			HelpLink = "https://github.com/jstedfast/MailKit/blob/master/FAQ.md#InvalidSslCertificate";
		}

		public SslHandshakeException(string message)
			: base(message)
		{
			HelpLink = "https://github.com/jstedfast/MailKit/blob/master/FAQ.md#InvalidSslCertificate";
		}

		public SslHandshakeException()
			: base("An error occurred while attempting to establish an SSL or TLS connection.")
		{
			HelpLink = "https://github.com/jstedfast/MailKit/blob/master/FAQ.md#InvalidSslCertificate";
		}

		internal static SslHandshakeException Create(Exception ex, bool starttls)
		{
			string text = "An error occurred while attempting to establish an SSL or TLS connection." + Environment.NewLine + Environment.NewLine;
			if (ex is AggregateException ex2)
			{
				AggregateException ex3 = ex2.Flatten();
				ex = ((ex3.InnerExceptions.Count != 1) ? ex3 : ex3.InnerExceptions[0]);
			}
			if (starttls)
			{
				text += "The SSL certificate presented by the server is not trusted by the system for one or more of the following reasons:";
			}
			else
			{
				text = text + "One possibility is that you are trying to connect to a port which does not support SSL/TLS." + Environment.NewLine;
				text += Environment.NewLine;
				text += "The other possibility is that the SSL certificate presented by the server is not trusted by the system for one or more of the following reasons:";
			}
			text += Environment.NewLine;
			text = text + "1. The server is using a self-signed certificate which cannot be verified." + Environment.NewLine;
			text = text + "2. The local system is missing a Root or Intermediate certificate needed to verify the server's certificate." + Environment.NewLine;
			text = text + "3. The certificate presented by the server is expired or invalid." + Environment.NewLine;
			text += Environment.NewLine;
			text += "See https://github.com/jstedfast/MailKit/blob/master/FAQ.md#InvalidSslCertificate for possible solutions.";
			return new SslHandshakeException(text, ex);
		}
	}
