namespace MailKit.Search
{
	public class BinarySearchQuery : SearchQuery
	{
		public SearchQuery Left { get; private set; }

		public SearchQuery Right { get; private set; }

		public BinarySearchQuery(SearchTerm term, SearchQuery left, SearchQuery right)
			: base(term)
		{
			if (left == null)
			{
				throw new ArgumentNullException("left");
			}
			if (right == null)
			{
				throw new ArgumentNullException("right");
			}
			Right = right;
			Left = left;
		}

		internal override SearchQuery Optimize(ISearchQueryOptimizer optimizer)
		{
			SearchQuery searchQuery = Right.Optimize(optimizer);
			SearchQuery searchQuery2 = Left.Optimize(optimizer);
			SearchQuery expr = ((searchQuery2 == Left && searchQuery == Right) ? this : new BinarySearchQuery(base.Term, searchQuery2, searchQuery));
			return optimizer.Reduce(expr);
		}
	}
	public class DateSearchQuery : SearchQuery
	{
		public DateTime Date { get; private set; }

		public DateSearchQuery(SearchTerm term, DateTime date)
			: base(term)
		{
			Date = date;
		}
	}
	public class FilterSearchQuery : SearchQuery
	{
		public string Name { get; private set; }

		public FilterSearchQuery(string name)
			: base(SearchTerm.Filter)
		{
			if (name == null)
			{
				throw new ArgumentNullException("name");
			}
			if (name.Length == 0)
			{
				throw new ArgumentException("The filter name cannot be empty.", "name");
			}
			Name = name;
		}

		public FilterSearchQuery(MetadataTag filter)
			: base(SearchTerm.Filter)
		{
			if (filter.Id.StartsWith("/private/filters/values/", StringComparison.Ordinal))
			{
				Name = filter.Id.Substring("/private/filters/values/".Length);
				return;
			}
			if (filter.Id.StartsWith("/shared/filters/values/", StringComparison.Ordinal))
			{
				Name = filter.Id.Substring("/shared/filters/values/".Length);
				return;
			}
			throw new ArgumentException("Metadata tag does not reference a valid filter.", "filter");
		}
	}
	public class HeaderSearchQuery : SearchQuery
	{
		public string Field { get; private set; }

		public string Value { get; private set; }

		public HeaderSearchQuery(string field, string value)
			: base(SearchTerm.HeaderContains)
		{
			if (field == null)
			{
				throw new ArgumentNullException("field");
			}
			if (field.Length == 0)
			{
				throw new ArgumentException("Cannot search an empty header field name.", "field");
			}
			if (value == null)
			{
				throw new ArgumentNullException("value");
			}
			Field = field;
			Value = value;
		}
	}
