		GMailRaw
	}
	public enum SortOrder
	{
		None,
		Ascending,
		Descending
	}
	public class TextSearchQuery : SearchQuery
	{
		public string Text { get; private set; }

		public TextSearchQuery(SearchTerm term, string text)
			: base(term)
		{
			if (text == null)
			{
				throw new ArgumentNullException("text");
			}
			if (text.Length == 0)
			{
				throw new ArgumentException("Cannot search for an empty string.", "text");
			}
			Text = text;
		}
	}
	public class UidSearchQuery : SearchQuery
	{
		public new IList<UniqueId> Uids { get; private set; }

		public UidSearchQuery(IList<UniqueId> uids)
			: base(SearchTerm.Uid)
		{
			if (uids == null)
			{
				throw new ArgumentNullException("uids");
			}
			if (uids.Count == 0)
			{
				throw new ArgumentException("Cannot search for an empty set of unique identifiers.", "uids");
			}
			Uids = uids;
		}

		public UidSearchQuery(UniqueId uid)
			: base(SearchTerm.Uid)
		{
			if (!uid.IsValid)
			{
				throw new ArgumentException("Cannot search for an invalid unique identifier.", "uid");
			}
			Uids = new UniqueIdSet(SortOrder.Ascending);
			Uids.Add(uid);
		}
	}
	public class UnarySearchQuery : SearchQuery
	{
		public SearchQuery Operand { get; private set; }

		public UnarySearchQuery(SearchTerm term, SearchQuery operand)
			: base(term)
		{
			if (operand == null)
			{
				throw new ArgumentNullException("operand");
			}
			Operand = operand;
		}

		internal override SearchQuery Optimize(ISearchQueryOptimizer optimizer)
		{
			SearchQuery searchQuery = Operand.Optimize(optimizer);
			SearchQuery expr = ((searchQuery == Operand) ? this : new UnarySearchQuery(base.Term, searchQuery));
			return optimizer.Reduce(expr);
		}
	}
