					Buffer.BlockCopy(input, inputIndex, input, 0, num);
					inputEnd = num;
					inputIndex = 0;
				}
			}
			else
			{
				inputIndex = 0;
				inputEnd = 0;
			}
			num = input.Length - inputEnd;
			int index = inputEnd;
			try
			{
				int num2;
				if (!(Stream is NetworkStream))
