					cancellationToken.ThrowIfCancellationRequested();
					num2 = ((!doAsync) ? Stream.Read(input, index, num) : (await Stream.ReadAsync(input, index, num, cancellationToken).ConfigureAwait(continueOnCapturedContext: false)));
				}
				else if (doAsync)
