		private void CheckDisposed()
		{
			if (disposed)
			{
				throw new ObjectDisposedException("Pop3Client");
			}
		}

		private void CheckConnected()
		{
			if (!IsConnected)
			{
				throw new ServiceNotConnectedException("The Pop3Client is not connected.");
			}
		}

		private void CheckAuthenticated()
		{
			if (!IsAuthenticated)
			{
