			}
			else
			{
				network = stream;
				secure = false;
			}
			probed = ProbedCapabilities.None;
			if (network.CanTimeout)
			{
				network.WriteTimeout = timeout;
				network.ReadTimeout = timeout;
			}
			try
			{
