			{
				return new Stream[0];
			}
			int[] array = new int[count];
			for (int i = 0; i < count; i++)
			{
				array[i] = startIndex + i + 1;
			}
			return new DownloadStreamContext(this, progress).DownloadAsync(array, headersOnly, doAsync: false, cancellationToken).GetAwaiter().GetResult();
		}

		private Task DeleteMessageAsync(int index, bool doAsync, CancellationToken cancellationToken)
