			}
			int num;
			do
			{
				num = ((!doAsync) ? engine.Iterate() : (await engine.IterateAsync().ConfigureAwait(continueOnCapturedContext: false)));
			}
			while (num < pc.Id);
			for (int l = 0; l < commands.Length; l++)
