		private async Task FlushAsync(bool doAsync, CancellationToken cancellationToken)
		{
			CheckDisposed();
			if (outputIndex == 0)
			{
				return;
			}
			using (cancellationToken.Register(DropConnection))
			{
				_ = 1;
				try
				{
					if (doAsync)
					{
