		private async Task GetStreamsAsync(IList<UniqueId> uids, ImapFetchStreamCallback callback, bool doAsync, CancellationToken cancellationToken, ITransferProgress progress)
		{
			if (uids == null)
			{
				throw new ArgumentNullException("uids");
			}
			if (callback == null)
			{
				throw new ArgumentNullException("callback");
			}
			CheckState(open: true, rw: false);
			if (uids.Count == 0)
			{
				return;
			}
			FetchStreamCallbackContext ctx = new FetchStreamCallbackContext(this, callback, progress);
			string format = "UID FETCH %s (BODY.PEEK[])\r\n";
			try
			{
				foreach (ImapCommand ic in Engine.CreateCommands(cancellationToken, this, format, uids))
				{
					ic.RegisterUntaggedHandler("FETCH", FetchStreamAsync);
					ic.UserData = ctx;
					Engine.QueueCommand(ic);
					await Engine.RunAsync(ic, doAsync).ConfigureAwait(continueOnCapturedContext: false);
					ProcessResponseCodes(ic, null);
					if (ic.Response != ImapCommandResponse.Ok)
					{
						throw ImapCommandException.Create("FETCH", ic);
					}
				}
			}
			finally
			{
				ctx.Dispose();
			}
		}

		private async Task GetStreamsAsync(IList<int> indexes, ImapFetchStreamCallback callback, bool doAsync, CancellationToken cancellationToken, ITransferProgress progress)
		{
			if (indexes == null)
			{
				throw new ArgumentNullException("indexes");
			}
			if (callback == null)
			{
				throw new ArgumentNullException("callback");
			}
			CheckState(open: true, rw: false);
			CheckAllowIndexes();
			if (indexes.Count == 0)
			{
				return;
			}
			string arg = ImapUtils.FormatIndexSet(indexes);
			string format = $"FETCH {arg} (UID BODY.PEEK[])\r\n";
			ImapCommand ic = new ImapCommand(Engine, cancellationToken, this, format);
			FetchStreamCallbackContext ctx = new FetchStreamCallbackContext(this, callback, progress);
			ic.RegisterUntaggedHandler("FETCH", FetchStreamAsync);
			ic.UserData = ctx;
			Engine.QueueCommand(ic);
			try
			{
				await Engine.RunAsync(ic, doAsync).ConfigureAwait(continueOnCapturedContext: false);
				ProcessResponseCodes(ic, null);
				if (ic.Response != ImapCommandResponse.Ok)
				{
					throw ImapCommandException.Create("FETCH", ic);
				}
			}
			finally
			{
				ctx.Dispose();
			}
		}

		private async Task GetStreamsAsync(int min, int max, ImapFetchStreamCallback callback, bool doAsync, CancellationToken cancellationToken, ITransferProgress progress)
		{
			if (min < 0)
			{
				throw new ArgumentOutOfRangeException("min");
			}
			if (max != -1 && max < min)
			{
				throw new ArgumentOutOfRangeException("max");
			}
			if (callback == null)
			{
				throw new ArgumentNullException("callback");
			}
			CheckState(open: true, rw: false);
			CheckAllowIndexes();
			if (min == base.Count)
			{
				return;
			}
			string format = $"FETCH {GetFetchRange(min, max)} (UID BODY.PEEK[])\r\n";
			ImapCommand ic = new ImapCommand(Engine, cancellationToken, this, format);
			FetchStreamCallbackContext ctx = new FetchStreamCallbackContext(this, callback, progress);
			ic.RegisterUntaggedHandler("FETCH", FetchStreamAsync);
			ic.UserData = ctx;
			Engine.QueueCommand(ic);
			try
			{
				await Engine.RunAsync(ic, doAsync).ConfigureAwait(continueOnCapturedContext: false);
				ProcessResponseCodes(ic, null);
				if (ic.Response != ImapCommandResponse.Ok)
				{
					throw ImapCommandException.Create("FETCH", ic);
				}
			}
			finally
			{
				ctx.Dispose();
			}
		}

