								Stream.Write(output, 0, 4096);
							}
							logger.LogClient(output, 0, 4096);
							outputIndex = 0;
						}
						if (outputIndex != 0)
						{
							continue;
						}
						while (left >= 4096)
						{
							if (doAsync)
							{
								await Stream.WriteAsync(buffer, index, 4096, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
							}
							else
							{
