						Stream.Write(output, 0, outputIndex);
						Stream.Flush();
					}
					logger.LogClient(output, 0, outputIndex);
					outputIndex = 0;
				}
				catch (Exception ex)
				{
					IsConnected = false;
					if (!(ex is OperationCanceledException))
					{
						cancellationToken.ThrowIfCancellationRequested();
					}
					throw;
				}
			}
		}

